 1	import * as React from 'react';
 2	import { PageSection } from '@patternfly/react-core';
 3	import { Formik } from 'formik';
 4	import * as _ from 'lodash';
 5	import { useTranslation } from 'react-i18next';
 6	import PipelineRunParameters from './PipelineRunParameters';
 7	import { K8sResourceKind } from '@openshift-console/dynamic-plugin-sdk';
 8	
 9	export interface PipelineRunParametersFormProps {
10	  obj: K8sResourceKind;
11	}
12	
13	const PipelineRunParametersForm: React.FC<PipelineRunParametersFormProps> = ({
14	  obj,
15	}) => {
16	  const { t } = useTranslation('plugin__pipelines-console-plugin');
17	  const initialValues = {
18	    parameters: _.get(obj.spec, 'params', []),
19	  };
20	  return (
21	    <>
22	      <Formik initialValues={initialValues} onSubmit={null}>
23	        {() => (
24	          <PageSection
25	            variant="light"
26	            isFilled
27	            className="pipelines-console-plugin__page-section-width pf-v6-u-p-0 pipelines-console-plugin__background-transparent"
28	          >
29	            <PipelineRunParameters
30	              fieldName="parameters"
31	              isReadOnly
32	              nameLabel={t('Name')}
33	              nameFieldName="name"
34	              valueLabel={t('Value')}
35	              valueFieldName="value"
36	              emptyMessage={t(
37	                'No parameters are associated with this PipelineRun.',
38	              )}
39	              emptyValues={{
40	                name: '',
41	                value: '',
42	              }}
43	              className="pipelines-console-plugin__background-transparent"
44	            />
45	          </PageSection>
46	        )}
47	      </Formik>
48	    </>
49	  );
50	};
51	
52	export default PipelineRunParametersForm;

